#include <set>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    int n = code.size();
    vector<pair<string, string>> validCoupons;
    set<string> validBusinesses = {"electronics", "grocery", "pharmacy", "restaurant"};
    regex codeRegex("^[a-zA-Z0-9_]+$");
    map<string, int> businessOrder = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    for (int i = 0; i < n; ++i) {
        string c = code[i];
        string b = businessLine[i];
        bool a = isActive[i];

        if (c.empty() || !regex_match(c, codeRegex)) continue;
        if (validBusinesses.find(b) == validBusinesses.end()) continue;
        if (!a) continue;

        validCoupons.push_back({b, c});
    }

    auto compare = [](const pair<string, string>& a, const pair<string, string>& b) {
        int orderA = businessOrder[a.first];
        int orderB = businessOrder[b.first];
        if (orderA != orderB) return orderA < orderB;
        return a.second < b.second;
    };

    sort(validCoupons.begin(), validCoupons.end(), compare);

    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.second);
    }

    return result;
}
